test_cases.assertion_pseudocode:
db = initialize_database("./data/af-hub.db")
stats = db.Stats()
// Default MaxOpenConns is 0 (unlimited)
assert stats.MaxOpenConnections == 0
// No explicit SetMaxIdleConns call was made (default is 2)
// Verify by checking that no custom limit was set programmatically
assert db_has_no_explicit_max_open_conns_override() == true
assert pragma_busy_timeout_is_set(db, 5000) == true

response = http_get("http://localhost:8080/healthz")
assert response.status_code == 200
assert parse_json(response.body) == {"status": "ok"}

response = http_get("http://localhost:8080/readyz")
assert response.status_code == 200
assert parse_json(response.body) == {"status": "ready"}

// Health probe accessible without auth
r1 = http_get("/healthz")
assert r1.status_code == 200

// Protected route requires auth
r2 = http_get("/api/v1/some-endpoint")  // no auth header
assert r2.status_code == 401

// Auth group has no auth middleware (route returns 404, not 401, for unregistered paths)
r3 = http_get("/api/v1/auth/oauth/callback")  // no auth header
assert r3.status_code != 401  // should be 404 or route-specific, not auth rejection

response = http_get("/api/v1/auth/test-route")  // no Authorization header
// The auth middleware should not have been invoked
assert response.status_code != 401  // no auth challenge
// 404 is acceptable since no handler is registered at this path yet
assert response.status_code in [404, 200]

// In a test handler registered after auth middleware:
handler = func(c echo.Context) error {
  auth = c.Get(string(AuthContextKey)).(*AuthContext)
  assert auth != nil
  assert auth.CredentialType != ""
  return c.JSON(200, auth)
}
response = invoke_protected_route_with_valid_token(handler)
assert response.status_code == 200

// Static analysis / code review assertion:
source_files = scan_source_files("internal/middleware/auth*.go")
for cred_type in ["admin_token", "api_key", "workspace_token"]:
  hash_comparison = find_hash_comparison_in_source(source_files, cred_type)
  assert uses_constant_time_compare(hash_comparison) == true
  assert uses_bytes_equal(hash_comparison) == false
